import{_ as e,c as t,o as s,a4 as o}from"./chunks/framework.ttppV29E.js";const f=JSON.parse('{"title":"Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"docs/configuration/permissions.md","filePath":"docs/configuration/permissions.md","lastUpdated":1775835030000}'),i={name:"docs/configuration/permissions.md"},a=o('<h1 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h1><p>Permissions, policies and roles are configured in <a href="https://identity.aireinnovate.com" target="_blank" rel="noreferrer">AireIdentity</a>.</p><h2 id="resource-restrictions" tabindex="-1">Resource Restrictions <a class="header-anchor" href="#resource-restrictions" aria-label="Permalink to &quot;Resource Restrictions&quot;">​</a></h2><p>Resource restrictions are used to restrict access to specific resources based on the user&#39;s roles. They are defined by using the <a href="https://docs.identity.aireinnovate.com/docs/policy-management/" target="_blank" rel="noreferrer">policy feature</a> in AireIdentity.</p><div class="tip custom-block"><p class="custom-block-title">Example: Task Editing</p><p>Given you have a task with the key <code>my-task</code> within a workflow with the key <code>my-workflow</code>.</p><p>You can define the following statements:</p><ul><li><code>Workflow/*</code> - This targets all edits to all tasks from all workflows.</li><li><code>Workflow/my-workflow</code> - This targets all edits to all tasks from <code>my-workflow</code>.</li><li><code>Task/*</code> - This targets all edits to all tasks.</li><li><code>Task/my-task</code> - This targets all edits to <code>my-task</code>.</li><li><code>Task/*/Property/Assignee</code> - This targets edits to the assignee for all tasks.</li><li><code>Task/my-task/Property/Assignee</code> - This targets edits to the assignee for <code>my-task</code>.</li><li><code>Task/*/Property/Status</code> - This targets edits to the status for all tasks.</li><li><code>Task/my-task/Property/Status</code> - This targets edits to the status for <code>my-task</code>.</li><li><code>Task/my-task/Property/Status/Cancelled</code> - This targets edits transitioning to the <code>Cancelled</code> status for <code>my-task</code>.</li><li><code>Property/Assignee</code> - This targets edits to the assignee for all tasks.</li><li><code>Property/Status</code> - This targets edits to the status for all tasks.</li><li><code>Property/Status/Completed</code> - This targets edits transitioning to the <code>Completed</code> status for all tasks</li></ul></div>',5),r=[a];function c(l,d,n,h,p,m){return s(),t("div",null,r)}const u=e(i,[["render",c]]);export{f as __pageData,u as default};
